```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"

using namespace sqlgen;
using namespace sqlgen::literals;

namespace detail {

// Map a runtime table name to a compile‑time type and run a functor on it.
template <typename F>
void with_table_type(const std::string& table_name, F&& f) {
  if (table_name == "Student") {
    f.template operator()<Student>();
  } else if (table_name == "Course") {
    f.template operator()<Course>();
  } else if (table_name == "Score") {
    f.template operator()<Score>();
  } else if (table_name == "Major") {
    f.template operator()<Major>();
  } else {
    throw std::runtime_error("Unknown table name: " + table_name);
  }
}

// Helper to build an empty instance of table type and set a single field by
// compile‑time index.
template <std::size_t I, typename T, typename Value>
void set_field(T& obj, Value&& v) {
  rfl::for_each(obj, [&](auto& field, std::size_t idx) {
    if (idx == I) {
      using FieldType = std::decay_t<decltype(field)>;
      if constexpr (std::is_same_v<FieldType, std::optional<typename FieldType::value_type>>) {
        field = typename FieldType::value_type(std::forward<Value>(v));
      } else {
        field = FieldType(std::forward<Value>(v));
      }
    }
  });
}

// Get the index of a named field at compile time.
template <typename T>
std::size_t field_index(const std::string& col_name) {
  std::size_t idx = static_cast<std::size_t>(-1);
  std::size_t current = 0;
  rfl::for_each(T{}, [&](auto& field, auto name) {
    (void)field;
    if (idx == static_cast<std::size_t>(-1) &&
        std::string{name.c_str()} == col_name) {
      idx = current;
    }
    ++current;
  });
  if (idx == static_cast<std::size_t>(-1)) {
    throw std::runtime_error("Unknown column name: " + col_name);
  }
  return idx;
}

// Create a WHERE clause for primary key equality using sqlgen helpers.
template <typename T>
auto primary_key_eq(const typename sqlgen::primary_key_type<T>::type& id) {
  // primary_key_column_name<T>() returns the column name as a string literal.
  constexpr auto pk_name = sqlgen::primary_key_column_name<T>();
  return sqlgen::where(sqlgen::col<pk_name> == id);
}

}  // namespace detail

// Insert records into a table in the EAS database.
// `T` is the C++ model type corresponding to the table.
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  if (records.empty()) return;

  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_result.error().message());
  }
  auto& conn = conn_result.value();

  // Insert each record.
  for (const auto& rec : records) {
    auto res = sqlgen::insert(rec).into<T>().execute(conn);
    if (!res) {
      throw std::runtime_error("Insert failed: " + res.error().message());
    }
  }
}

// Modify a record in a table based on primary key ID.
// `new_value` is passed as std::string and converted by sqlgen/sqlite.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value) {
  detail::with_table_type(table_name, [&](auto tag) {
    using T = decltype(tag.template operator()<void>(), void(), Student); // dummy
  });
}

// A concrete implementation of modify and delete that works for all tables
// by dispatching on the table name and using sqlgen’s reflection.
template <typename IdType, typename ValueType>
void modify_eas_record_typed(const std::string& table_name,
                             const IdType& record_id,
                             const std::string& col_name,
                             const ValueType& new_value) {
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_result.error().message());
  }
  auto& conn = conn_result.value();

  detail::with_table_type(table_name, [&](auto tmpl_tag) {
    using T = std::decay_t<decltype(tmpl_tag.template operator()<Student>(), Student{})>;
    (void)tmpl_tag;

    // Build partial object with only the target column set.
    T obj{};
    std::size_t idx = detail::field_index<T>(col_name);

    // Set field by index using runtime dispatch.
    std::size_t current = 0;
    rfl::for_each(obj, [&](auto& field, auto name) {
      (void)name;
      if (current == idx) {
        using FieldType = std::decay_t<decltype(field)>;
        if constexpr (sqlgen::is_primary_key<FieldType>::value) {
          // Never modify primary key.
        } else {
          if constexpr (std::is_same_v<FieldType, std::optional<typename FieldType::value_type>>) {
            using V = typename FieldType::value_type;
            field = V(new_value);
          } else {
            field = FieldType(new_value);
          }
        }
      }
      ++current;
    });

    // WHERE primary key = record_id
    auto where_clause = detail::primary_key_eq<T>(record_id);
    auto res = sqlgen::update(obj).table<T>().where(where_clause).execute(conn);
    if (!res) {
      throw std::runtime_error("Update failed: " + res.error().message());
    }
  });
}

// Wrapper with prescribed signature: primary key ID and new value
// are string-typed; conversion is deferred to sqlgen/SQLite.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const std::string& new_value) {
  modify_eas_record_typed(table_name, record_id, col_name, new_value);
}

// Delete a record from a table based on primary key ID (string typed).
inline void delete_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id) {
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database: " +
                             conn_result.error().message());
  }
  auto& conn = conn_result.value();

  detail::with_table_type(table_name, [&](auto tmpl_tag) {
    using T = std::decay_t<decltype(tmpl_tag.template operator()<Student>(), Student{})>;
    (void)tmpl_tag;

    // WHERE primary key = record_id
    auto where_clause = detail::primary_key_eq<T>(record_id);
    auto res = sqlgen::remove_from<T>().where(where_clause).execute(conn);
    if (!res) {
      throw std::runtime_error("Delete failed: " + res.error().message());
    }
  });
}
