  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // 2. Create Course and Enrollment tables (if they don't already exist)
  orm::Table<Course> courseTable("Course");
  orm::Table<Enrollment> enrollmentTable("Enrollment");

  courseTable
      .column(&Course::course_id, "course_id")
      .column(&Course::title, "title");

  enrollmentTable
      .column(&Enrollment::enrollment_id, "enrollment_id")
      .column(&Enrollment::course_id, "course_id")
      .column(&Enrollment::grade, "grade");

  // Create tables in the database
  orm::createTable(conn, courseTable);
  orm::createTable(conn, enrollmentTable);

  // 3. Define a view corresponding to the aggregation query
  orm::View<CourseStatsView> statsView(
      "CourseStatsView",
      "SELECT c.title AS title, "
      "       COUNT(e.enrollment_id) AS student_count, "
      "       AVG(e.grade) AS avg_grade "
      "FROM Course c "
      "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
      "GROUP BY c.course_id, c.title");

  statsView
      .column(&CourseStatsView::title, "title")
      .column(&CourseStatsView::student_count, "student_count")
      .column(&CourseStatsView::avg_grade, "avg_grade");

  // 4. Query the database and map results to CourseStats
  std::vector<CourseStatsView> viewRows;
  orm::select(conn, statsView, viewRows);

  std::vector<CourseStats> result;
  result.reserve(viewRows.size());

  for (const auto &row : viewRows) {
    CourseStats stats;
    stats.title = row.title;
    stats.student_count = row.student_count;
    stats.avg_grade = row.avg_grade;  // NULLs from AVG become std::nullopt
    result.push_back(std::move(stats));
  }

  return result;
}

}  // namespace query_course_enrollment_stats
