std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // 1. Connect to the SQLite database "test_db.sqlite"
  sqlite::Database db("test_db.sqlite");

  // 2. Create tables for the schema (idempotent, uses sqlgen metadata)
  db.create_table<Customer>();
  db.create_table<Product>();
  db.create_table<Order>();
  db.create_table<OrderItem>();

  // 3. Prepare the query to retrieve purchase history for a specific customer
  // Reference SQL:
  // SELECT p.name, o.order_date, oi.quantity
  // FROM Customer c
  // JOIN "Order" o ON c.customer_id = o.customer_id
  // JOIN OrderItem oi ON o.order_id = oi.order_id
  // JOIN Product p ON oi.product_id = p.product_id
  // WHERE c.customer_id = ?
  // ORDER BY o.order_date DESC;

  const char* sql = R"SQL(
    SELECT p.name, o.order_date, oi.quantity
    FROM Customer c
    JOIN "Order" o ON c.customer_id = o.customer_id
    JOIN OrderItem oi ON o.order_id = oi.order_id
    JOIN Product p ON oi.product_id = p.product_id
    WHERE c.customer_id = ?
    ORDER BY o.order_date DESC
  )SQL";

  sqlite::Statement stmt = db.prepare(sql);
  stmt.bind(1, customer_id);

  std::vector<PurchaseHistory> results;

  // 4. Read and return the results as a vector of PurchaseHistory
  while (stmt.step()) {
    PurchaseHistory ph{
      .product_name = stmt.get<std::string>(0),
      .order_date   = stmt.get<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">>(1),
      .quantity     = stmt.get<int>(2)
    };
    results.push_back(std::move(ph));
  }

  return results;
}

}  // namespace query_customer_purchase_history
