std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  // Open a connection to the SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Start with the base SELECT query using sqlgen's query builder
  auto query = sqlgen::make_query<Book>(conn).select();

  // Dynamically build WHERE clauses based on non-null filters

  if (filters.title_keyword.has_value()) {
    // Use LIKE for title search with wildcard '%' around the keyword
    std::string pattern = "%" + *filters.title_keyword + "%";
    query = query.where(sqlgen::like(&Book::title, pattern));
