```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  if (ids.empty()) {
    // Nothing to delete; treat as success.
    return true;
  }

  try {
    // Open SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Create a context and map the Document struct to the "Document" table
    sqlgen::Context ctx(db);
    ctx.map<Document>("Document",
                      &Document::doc_id,
                      &Document::title,
                      &Document::is_deleted,
                      &Document::deleted_at);

    auto& documents = ctx.table<Document>();

    // Use a transaction to ensure atomic updates
    auto tx = db.transaction();

    // Current timestamp according to sqlgen
    auto now = sqlgen::DateTime::now();

    // If sqlgen supports bulk updates with IN clause:
    // documents.update()
    //     .set(&Document::is_deleted = 1, &Document::deleted_at = now)
    //     .where(in(&Document::doc_id, ids));
    //
    // However, to stay compatible with common sqlgen usage, update in a loop
    // inside the same transaction.
    for (int id : ids) {
      // Load the document by primary key
      auto docOpt = documents.get(id);
      if (!docOpt) {
        // If any specified id does not exist, you can either skip or fail.
        // Here we choose to fail and roll back.
        tx.rollback();
        return false;
      }

      auto& doc = *docOpt;
      doc.is_deleted = 1;
      doc.deleted_at = now;

      documents.update(doc);
    }

    tx.commit();
    return true;
  } catch (...) {
    // On any error, indicate failure.
    return false;
  }
}

}  // namespace soft_delete_records
```

