```cpp
#pragma once

#include <stdexcept>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;

  if (amount <= 0.0) {
    return false;
  }

  // Open connection to the SQLite database
  sqlite::Database db("test_db.sqlite");

  try {
    // Start transaction
    db.begin_transaction();

    // Create a table abstraction for Account
    auto accounts = make_table<Account>(db, "Account");

    // 1) Check that the sender exists and has sufficient balance
    auto from_opt = accounts.get(from_account_id);
    if (!from_opt) {
      db.rollback();
      return false;
    }

    Account from = *from_opt;
    if (from.balance < amount) {
      db.rollback();
      return false;
    }

    // 2) Deduct from sender
    from.balance -= amount;
    accounts.update(from);  // update by primary key

    // 3) Ensure the receiver exists
    auto to_opt = accounts.get(to_account_id);
    if (!to_opt) {
      db.rollback();
      return false;
    }

    Account to = *to_opt;

    // 4) Add to receiver
    to.balance += amount;
    accounts.update(to);  // update by primary key

    // 5) Commit transaction
    db.commit();
    return true;
  } catch (...) {
    // Rollback on any failure and propagate the error
    try {
      db.rollback();
    } catch (...) {
      // ignore rollback failure
    }
    throw;
  }
}

}  // namespace transaction_transfer_funds
```

