void update_eas_table() {
  // Ensure initial schema (with Major table) exists
  design_eas_database_with_major();

  auto result = sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // Always keep foreign key checks enabled
        return sqlgen::exec(conn, "PRAGMA foreign_keys = ON;")
            // 1. Add a new non-null column Grade to Score: char(1) NOT NULL
            .and_then([&conn](auto&&) {
              return sqlgen::exec(
                  conn,
                  "ALTER TABLE Score "
                  "ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT ' ';");
            })
            // 2. Modify Student.Age to INT NULL
            //
            // SQLite does not support ALTER COLUMN type change directly,
            // so we recreate the Student table without specifying NOT NULL
            // on Age and copy data over. If Age did not exist before, this
            // will simply create it.
            .and_then([&conn](auto&&) {
              // Create a new table with the desired schema
              return sqlgen::exec(
                         conn,
                         "CREATE TABLE IF NOT EXISTS Student_new ("
                         "  SNo    VARCHAR(10) PRIMARY KEY,"
                         "  SName  VARCHAR(30),"
                         "  Sex    INTEGER DEFAULT 1,"
                         "  Birthday DATETIME,"
                         "  Major  INTEGER,"
                         "  Scorses REAL DEFAULT 0.0,"
                         "  Remark TEXT,"
                         "  Age    INTEGER"
                         ");")
                  // Copy existing data; Age will be NULL by default
                  .and_then([&conn](auto&&) {
                    return sqlgen::exec(
                        conn,
                        "INSERT INTO Student_new "
                        "(SNo, SName, Sex, Birthday, Major, Scorses, Remark) "
                        "SELECT SNo, SName, Sex, Birthday, Major, Scorses, Remark "
                        "FROM Student;");
                  })
                  // Replace old Student table with the new one
                  .and_then([&conn](auto&&) {
                    return sqlgen::exec(conn, "DROP TABLE Student;");
                  })
                  .and_then([&conn](auto&&) {
                    return sqlgen::exec(
                        conn, "ALTER TABLE Student_new RENAME TO Student;");
                  });
            })
            // 3. Drop the Major table
            .and_then([&conn](auto&&) {
              return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
            });
      });

  // Propagate any error; throws on failure
  result.value();
}

} // namespace update_eas_table
