```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <cstdint>
#include <string>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into the Event table in the SQLite database
 * "test_db.sqlite", runs a query to extract date/time parts and compute
 * duration, and returns the results as a vector of TemporalAnalysis.
 *
 * Assumes the Event table already exists in the database with the schema
 * described in the documentation.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data (const std::vector<Event>& events)  {
  using namespace sqlgen;

  // Connect to the existing SQLite database.
  sqlite::Database db("test_db.sqlite");

  // Create a SQLGen context bound to this database.
  Context ctx(db);

  // Register the Event table mapping (assumes table "Event" exists).
  auto eventTable = ctx.registerTable<Event>("Event");

  // Insert provided events into the Event table.
  // This uses sqlgen's convenience insert; primary key is assumed
  // to be provided in the Event objects as per schema.
  for (const auto& ev : events) {
    eventTable.insert(ev);
  }

  // We will query temporal analysis directly using SQLite's date/time functions.
  //
  // SQLite-specific equivalents for the reference SQL:
  // - DAY(start_time)        -> CAST(STRFTIME('%d', start_time) AS INTEGER)
  // - MONTH(start_time)      -> CAST(STRFTIME('%m', start_time) AS INTEGER)
  // - YEAR(start_time)       -> CAST(STRFTIME('%Y', start_time) AS INTEGER)
  // - HOUR(start_time)       -> CAST(STRFTIME('%H', start_time) AS INTEGER)
  // - MINUTE(start_time)     -> CAST(STRFTIME('%M', start_time) AS INTEGER)
  // - SECOND(start_time)     -> CAST(STRFTIME('%S', start_time) AS INTEGER)
  // - WEEKDAY(start_time)    -> CAST(STRFTIME('%w', start_time) AS INTEGER)
  //                            (0=Sunday..6=Saturday)
  // - UNIXEPOCH(start_time)  -> STRFTIME('%s', start_time)
  // - DAYS_BETWEEN(a, b)     -> (JULIANDAY(b) - JULIANDAY(a))
  //
  // We filter on end_time IS NOT NULL so duration_days is always defined;
  // we still store it in an std::optional<double> for generality.

  const char* sql =
      "SELECT "
      "  event_id, "
      "  event_name, "
      "  CAST(STRFTIME('%d', start_time) AS INTEGER) AS start_day, "
      "  CAST(STRFTIME('%m', start_time) AS INTEGER) AS start_month, "
      "  CAST(STRFTIME('%Y', start_time) AS INTEGER) AS start_year, "
      "  CAST(STRFTIME('%H', start_time) AS INTEGER) AS start_hour, "
      "  CAST(STRFTIME('%M', start_time) AS INTEGER) AS start_minute, "
      "  CAST(STRFTIME('%S', start_time) AS INTEGER) AS start_second, "
      "  CAST(STRFTIME('%w', start_time) AS INTEGER) AS start_weekday, "
      "  CAST(STRFTIME('%s', start_time) AS INTEGER) AS start_epoch, "
      "  (JULIANDAY(end_time) - JULIANDAY(start_time)) AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL;";

  sqlite::Statement stmt(db, sql);

  std::vector<TemporalAnalysis> results;
  while (stmt.step()) {
    TemporalAnalysis ta;

    // Column indices follow the SELECT order above.
    ta.event_id      = stmt.columnInt(0);
    ta.event_name    = stmt.columnText(1);
    ta.start_day     = stmt.columnInt(2);
    ta.start_month   = stmt.columnInt(3);
    ta.start_year    = stmt.columnInt(4);
    ta.start_hour    = stmt.columnInt(5);
    ta.start_minute  = stmt.columnInt(6);
    ta.start_second  = stmt.columnInt(7);
    ta.start_weekday = stmt.columnInt(8);
    ta.start_epoch   = static_cast<int64_t>(stmt.columnInt64(9));

    if (stmt.columnType(10) == SQLITE_NULL) {
      ta.duration_days = std::nullopt;
    } else {
      ta.duration_days = stmt.columnDouble(10);
    }

    results.push_back(std::move(ta));
  }

  return results;
}

}  // namespace analyze_temporal_data
```

