/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Open SQLite database
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Create a write session
    sqlgen::Write<sqlgen::sqlite::Connection> writer(conn);

    // 1. Upsert items: insert or replace based on primary key
    for (const auto& item : items) {
      // sqlgen maps write().upsert<T>() to "INSERT OR REPLACE" for SQLite
      writer.upsert<Inventory>(item);
    }

    // 2. Read back and verify upsert behavior
    sqlgen::Read<sqlgen::sqlite::Connection> reader(conn);

    // Fetch all rows from Inventory table
    std::vector<Inventory> db_items = reader.all<Inventory>();

    // Build a simple verification: each input item must exist in db_items
    // with the same primary key and the same fields.
    for (const auto& input_item : items) {
      bool found = false;
      for (const auto& db_item : db_items) {
        if (db_item.item_id == input_item.item_id) {
          if (db_item.name != input_item.name ||
              db_item.quantity != input_item.quantity) {
            // Mismatch: upsert did not correctly replace the existing row
            return false;
          }
          found = true;
          break;
        }
      }
      if (!found) {
        // Input item not found in the table after upsert
        return false;
      }
    }

    return true;
  } catch (const std::exception&) {
    // Any failure (connection, SQL, mapping) is treated as a failed verification
    return false;
  }
}

}  // namespace upsert_inventory_items
