#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;

  // Connect to SQLite database
  sqlite::Database db("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite)
  db.execute(R"(PRAGMA foreign_keys = ON;)");

  // Drop tables if they exist (start with a clean slate)
  db.execute(R"(DROP TABLE IF EXISTS "Child";)");
  db.execute(R"(DROP TABLE IF EXISTS "Parent";)");

  // Create tables with appropriate constraints
  //
  // sqlgen::create_table will infer schema, including PK/FK constraints.
  // For SQLite, ON DELETE CASCADE must be part of the foreign key definition,
  // so we explicitly create the tables here to guarantee the behavior.
  db.execute(R"(
    CREATE TABLE "Parent" (
      "parent_id" INTEGER PRIMARY KEY,
      "name"      TEXT NOT NULL
    );
  )");

  db.execute(R"(
    CREATE TABLE "Child" (
      "child_id"  INTEGER PRIMARY KEY,
      "parent_id" INTEGER,
      "note"      TEXT,
      FOREIGN KEY("parent_id") REFERENCES "Parent"("parent_id") ON DELETE CASCADE
    );
  )");

  // Create ORM table handles
  auto parents = make_table<Parent>(db, "Parent");
  auto children = make_table<Child>(db, "Child");

  // Insert a parent record
  Parent p;
  p.parent_id = 1;
  p.name = "Parent 1";
  parents.insert(p);

  // Insert a child record referencing the parent
  Child c;
  c.child_id = 1;
  c.parent_id = 1;
  c.note = "Child of Parent 1";
  children.insert(c);

  // Verify there is exactly one child before deletion
  {
    auto all_children = children.select_all();
    if (all_children.size() != 1) {
      return false;
    }
  }

  // Delete the parent
  parents.erase(p);

  // After deleting the parent, check if child rows were removed by cascade
  auto remaining_children = children.select_all();
  return remaining_children.empty();
}

}  // namespace cascade_delete_demo
