#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  try {
    // Connect to SQLite database "test_db.sqlite"
    sqlgen::sqlite::Connection conn{"test_db.sqlite"};

    // Create an ORM instance for the Account table
    auto orm = sqlgen::orm<Account>("Account", conn);

    // 1. Create Account table (drop if exists to make the example deterministic)
    orm.dropTableIfExists();
    orm.createTable();

    // Insert some initial rows to update
    orm.insert(Account{1, 100.0, "inactive"});
    orm.insert(Account{2, 250.5, "inactive"});
    orm.insert(Account{3, 500.0, "pending"});

    // 2. Update balances and statuses using set(...)

    // Example: give all accounts a 10% balance increase and set status to "active"
    orm.update()
        .set(&Account::balance = &Account::balance * 1.10,
             &Account::status  = "active")
        .exec();

    // Additional targeted update using WHERE clause:
    // Set status to "vip" for accounts with balance over 400 after the increase.
    orm.update()
        .set(&Account::status = "vip")
        .where(&Account::balance > 400.0)
        .exec();

    // 3. Verify changes persisted

    // Reload all rows and check expected values
    auto all_accounts = orm.select().exec();

    if (all_accounts.size() != 3) {
      return false;
    }

    // Check each account
    for (const auto &acc : all_accounts) {
      // All should be at least "active" or "vip"
      if (!(acc.status == "active" || acc.status == "vip")) {
        return false;
      }

      // Verify balance was increased by about 10%
      // We know original balances were 100.0, 250.5, and 500.0
      double expected = 0.0;
      if (acc.account_id == 1) expected = 100.0 * 1.10;
      if (acc.account_id == 2) expected = 250.5 * 1.10;
      if (acc.account_id == 3) expected = 500.0 * 1.10;

      // Allow small floating-point tolerance
      const double eps = 1e-6;
      if (std::abs(acc.balance - expected) > eps) {
        return false;
      }

      // For account 3 (largest balance), status should be "vip"
      if (acc.account_id == 3 && acc.status != "vip") {
        return false;
      }
    }

    return true;
  } catch (...) {
    // Any error means the update logic did not succeed
    return false;
  }
}

}  // namespace update_set_operations
```

