```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a
 * supplier and the name of a product, if any.
 *
 * Since SQLite does not support FULL OUTER JOIN directly, this uses UNION of
 * LEFT and RIGHT joins to simulate a full join:
 *
 *   SELECT s.name AS supplier_name, p.name AS product_name
 *   FROM Supplier s
 *   LEFT JOIN Product p ON s.supplier_id = p.supplier_id
 *   UNION
 *   SELECT s.name AS supplier_name, p.name AS product_name
 *   FROM Product p
 *   LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id;
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // Open connection to the SQLite database
  sqlite::connection conn{"test_db.sqlite"};

  // Define schema metadata for the existing tables
  auto supplierTable = make_table<Supplier>("Supplier",
                                            &Supplier::supplier_id,
                                            &Supplier::name);

  auto productTable = make_table<Product>("Product",
                                          &Product::product_id,
                                          &Product::supplier_id,
                                          &Product::name);

  // Aliases for convenience
  auto s = supplierTable.as("s");
  auto p = productTable.as("p");

  // Column references
  auto s_id   = column(&Supplier::supplier_id, s);
  auto s_name = column(&Supplier::name, s);
  auto p_id   = column(&Product::product_id, p);
  auto p_sup  = column(&Product::supplier_id, p);
  auto p_name = column(&Product::name, p);

  // LEFT JOIN: all suppliers, matching products (if any)
  auto left_join_query = select(s_name.as("supplier_name"),
                                p_name.as("product_name"))
                           .from(s)
                           .left_join(p, s_id == p_sup);

  // RIGHT JOIN (simulated): all products, matching suppliers (if any)
  // This is implemented as LEFT JOIN with the tables swapped.
  auto right_join_query = select(s_name.as("supplier_name"),
                                 p_name.as("product_name"))
                            .from(p)
                            .left_join(s, p_sup == s_id);

  // FULL OUTER JOIN simulation via UNION of LEFT and RIGHT
  auto full_join_query = left_join_query.union_all(right_join_query);

  std::vector<SupProd> result;

  // Execute the query and map rows into SupProd
  full_join_query.execute(conn, [&](const std::string &supplier_name_val,
                                    const std::optional<std::string> &product_name_val) {
    SupProd sp;
    sp.supplier_name = supplier_name_val;
    sp.product_name = product_name_val;
    result.push_back(std::move(sp));
  });

  return result;
}

}  // namespace full_join_suppliers_products
```

