/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating SQL tables in the SQLite database "test_db.sqlite", inserting the
 * provided rows, and executing a variety of join queries to produce join-output
 * samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::Connection conn("test_db.sqlite");

  // Create a storage object describing the schema we want to work with.
  // This uses sqlgen's reflection to map the C++ structs to SQL tables.
  auto storage = make_storage(
      conn,
      make_table("Department",
                 make_column("department_id", &Department::department_id,
                             primary_key()),
                 make_column("department_name", &Department::department_name),
                 make_column("location", &Department::location)),
      make_table("Employee",
                 make_column("employee_id", &Employee::employee_id,
                             primary_key()),
                 make_column("department_id", &Employee::department_id),
                 make_column("first_name", &Employee::first_name),
                 make_column("last_name", &Employee::last_name),
                 make_column("salary", &Employee::salary)));

  // Recreate the tables so that each call uses only the provided input data.
  storage.drop_table_if_exists<Department>();
  storage.drop_table_if_exists<Employee>();
  storage.sync_schema();  // create tables according to the schema

  // Insert provided departments and employees
  for (const auto &d : depts) {
    storage.insert(d);
  }
  for (const auto &e : emps) {
    storage.insert(e);
  }

  JoinAnalysis analysis;

  // Helper lambda to map query row to JoinResult
  auto make_join_result = [](const std::optional<std::string> &dept_name,
                             const std::optional<std::string> &first_name,
                             const std::optional<std::string> &last_name,
                             const std::optional<double> &salary) {
    JoinResult jr;
    jr.department_name = dept_name;
    jr.first_name = first_name;
    jr.last_name = last_name;
    jr.salary = salary;
    return jr;
  };

  // 1. INNER JOIN: employees with assigned departments
  {
    // SELECT d.department_name, e.first_name, e.last_name, e.salary
    // FROM Department d
    // INNER JOIN Employee e ON d.department_id = e.department_id;
    auto rows = storage.select(
        columns(&Department::department_name,
                &Employee::first_name,
                &Employee::last_name,
                &Employee::salary),
        inner_join<Department, Employee>(
            on(c(&Department::department_id) == &Employee::department_id)));

    for (const auto &row : rows) {
      std::optional<std::string> dept_name = std::get<0>(row);
      std::optional<std::string> first_name = std::get<1>(row);
      std::optional<std::string> last_name = std::get<2>(row);
      std::optional<double> salary = std::get<3>(row);
      analysis.inner_join_results.push_back(
          make_join_result(dept_name, first_name, last_name, salary));
