  auto p = table<Product>("Product");
  auto s = table<Sales>("Sales");

  // Expression for total_sales = SUM(p.price * s.quantity)
  auto total_sales_expr = sum(p(&Product::price) * s(&Sales::quantity));

  // Build and execute the query
  auto stmt = select(
                 p(&Product::product_id),
