              .order_by(desc(total_sales_expr))
              .limit(static_cast<int>(limit_count))
              .prepare(conn);

  std::vector<TopProduct> results;
  results.reserve(limit_count);

  // Iterate over the result set and populate TopProduct objects
  while (stmt.step()) {
