bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  auto& conn = conn_res.value();

  // Ensure the Product table exists (no-op if already created)
  auto create_res = create_table<Product>(conn);
  if (!create_res) return false;

  // Begin a transaction to ensure atomicity
  auto txn_res = begin_transaction(conn);
  if (!txn_res) return false;
  auto txn = txn_res.value();

  // Prepare the UPDATE statement once and reuse it
  // Equivalent SQL: UPDATE Product SET stock = stock + ? WHERE product_id = ?;
  auto stmt_res = prepare<Product>(
      txn,
      "UPDATE"_sql
      , "Product"_tbl
      , "SET"_sql, "stock"_col = "stock"_col + value<int>()
      , "WHERE"_sql, "product_id"_col == value<int>()
  );
  if (!stmt_res) {
    // Rollback on failure to prepare
    auto _ = rollback(txn);
    return false;
  }
  auto stmt = stmt_res.value();

  // Execute the prepared statement for each product in the shipment
  for (const auto& [pid, qty] : received) {
    // Bind: quantity_received then product_id
    auto exec_res = execute(stmt, qty, pid);
    if (!exec_res) {
      // Rollback entire transaction on any failure
      auto _ = rollback(txn);
      return false;
    }
  }

  // Commit the transaction if all updates succeeded
  auto commit_res = commit(txn);
  return commit_res.has_value();
