#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;         // 0–6 (Sunday–Saturday, SQLite strftime('%w', ...))
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open connection to the SQLite database.
  sqlite::connection db("test_db.sqlite");

  // Register the Sales table metadata with sqlgen.
  auto salesTable = make_table<Sales>("Sales",
                                      &Sales::sale_id, "sale_id",
                                      &Sales::product_id, "product_id",
                                      &Sales::quantity, "quantity",
                                      &Sales::sale_time, "sale_time");

  // Explicitly register the database with its tables (if required by sqlgen).
  auto database = make_database(db, salesTable);

  // Use a raw SQL query to:
  // 1. Extract weekday from sale_time using SQLite's strftime('%w', sale_time)
  // 2. Aggregate total quantity per weekday
  //
  // Note: SQLite's strftime('%w', ...) returns:
  //       0 = Sunday, 1 = Monday, ..., 6 = Saturday.
  const char* sql = R"SQL(
    SELECT
      CAST(strftime('%w', sale_time) AS INTEGER) AS weekday,
      SUM(quantity) AS total_quantity
    FROM Sales
    GROUP BY weekday
    ORDER BY weekday;
  )SQL";

  std::vector<WeekdayStats> results;

  sqlite::statement stmt(db, sql);
  while (stmt.step()) {
    WeekdayStats row{};
    // Column 0: weekday (int), Column 1: total_quantity (int)
    row.weekday = stmt.get_int(0);
    row.total_quantity = stmt.get_int(1);
    results.push_back(row);
  }

  return results;
}

}  // namespace weekday_sales_analysis
