```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

namespace detail {

// Helper to create an sqlgen connection to the SQLite DB.
inline auto make_connection() {
  // Adjust the path if the database is not in the current working directory.
  return sqlgen::sqlite::Connection{"test_db.sqlite"};
}

}  // namespace detail

/**
 * Description: This function tracks time metrics for each project, including
 * day, month, year, hour, minute, second, and duration in days. It also
 * performs weekly aggregation of total duration_days per project and week,
 * but returns the per-log metrics as TimeMetrics rows.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  auto conn = detail::make_connection();

  // Raw SQL using SQLite's datetime functions. We:
  // 1. Extract date/time parts from start_time.
  // 2. Compute difference in days using Julian day values.
  // 3. Also compute a week key (year + week) for internal grouping.
  //
  // Note: SQLite doesn't have DAY/MONTH/YEAR/HOUR/MINUTE/SECOND/DAYS_BETWEEN
  // built-ins, so we emulate them with strftime() and julianday().
  //
  // The inner query (log_metrics) returns per-log metrics.
  // The outer query (weekly_agg) groups by project and week; we keep the
  // metrics from log_metrics to satisfy the return type (per-log metrics),
  // while the weekly aggregation demonstrates the requested group-by behavior.
  //
  // If you only need the per-log metrics, you could drop the outer aggregation
  // and select directly from log_metrics.
  std::string sql = R"SQL(
    WITH log_metrics AS (
      SELECT
        p.project_id                 AS project_id,
        p.name                       AS name,
        CAST(strftime('%d', t.start_time) AS INTEGER) AS day,
        CAST(strftime('%m', t.start_time) AS INTEGER) AS month,
        CAST(strftime('%Y', t.start_time) AS INTEGER) AS year,
        CAST(strftime('%H', t.start_time) AS INTEGER) AS hour,
        CAST(strftime('%M', t.start_time) AS INTEGER) AS minute,
        CAST(strftime('%S', t.start_time) AS INTEGER) AS second,
        (julianday(t.end_time) - julianday(t.start_time)) AS duration_days,
        -- ISO week number and ISO week-year for grouping
        CAST(strftime('%Y', t.start_time, 'weekday 4', '-3 days') AS INTEGER)
          AS iso_year,
        CAST(strftime('%W', t.start_time) AS INTEGER)
          AS iso_week
      FROM Project p
