  // sqlgen::select<T> can map selected columns by name to the fields of T.
  auto result = sqlgen::select<TimeMetrics>(conn, sql);

  std::vector<TimeMetrics> metrics;
  metrics.reserve(result.size());
  for (auto &row : result) {
    metrics.push_back(row);
  }
  return metrics;
}

}  // namespace project_time_tracking

