  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;

  // Open SQLite database
  sqlite::connection conn("test_db.sqlite");

  // Register models so sqlgen knows about the tables and fields
  auto db = make_storage(
      conn,
      make_table("User",
                 make_column(&User::user_id, "user_id", primary_key()),
                 make_column(&User::name, "name")),
      make_table("Post",
                 make_column(&Post::post_id, "post_id", primary_key()),
                 make_column(&Post::user_id, "user_id"),
                 make_column(&Post::content, "content")));

  // Build and execute the SQL query:
  // SELECT
  //   User.user_id,
  //   User.name,
  //   COUNT(Post.post_id) AS post_count,
  //   AVG(LENGTH(Post.content)) AS avg_length
  // FROM User
  // LEFT JOIN Post ON User.user_id = Post.user_id
  // GROUP BY User.user_id, User.name;
  //
  // We map results into Stats; for the aggregated columns we use expressions.

  constexpr auto u = alias<User>("u");
  constexpr auto p = alias<Post>("p");

  auto rows = db.select(
      column(u, &User::user_id),
      column(u, &User::name),
      count(column(p, &Post::post_id)),
      avg(length(column(p, &Post::content))),
      from(u)
          .left_join(p, on(column(u, &User::user_id) == column(p, &Post::user_id)))
          .group_by(column(u, &User::user_id), column(u, &User::name)));

  std::vector<Stats> result;
  result.reserve(rows.size());

  for (auto &row : rows) {
    Stats s;
    // row is expected to be a tuple-like structure:
    // (user_id, name, post_count, avg_length)
    s.user_id = sqlgen::PrimaryKey<int>(std::get<0>(row));
    s.name = std::get<1>(row);
    s.post_count = static_cast<int>(std::get<2>(row));

    // AVG may return null if there are no posts for a user
    if constexpr (std::is_same_v<decltype(std::get<3>(row)), std::optional<double>>) {
      s.avg_length = std::get<3>(row);
    } else {
      // If the driver returns a nullable type in another way, adapt here.
      s.avg_length = std::get<3>(row);
    }

    result.push_back(std::move(s));
  }

  return result;
}

}  // namespace group_by_with_aggregations
